"use client";

import { useState, useEffect, useRef } from "react";
import storage from "./storage";

const HERO_IMG = "data:image/jpeg;base64,";
const PROFILE_IMG = "data:image/jpeg;base64,";
const SITTING_IMG = "data:image/jpeg;base64,";

// ─── 색상 팔레트 ─────────────────────────────────
// 메인: #E8002D (진파랑)  보조: #29ABE2 (스카이)  강조: #FFD600 (노랑)
// 배경: #F5F7FF  텍스트: #0A0F2C

const NAV_LINKS = ["홈", "소개", "공약", "소식", "의견함", "후원"];

const PLEDGES = [
  { icon: "🏥", title: "달빛어린이병원 설치", desc: "야간·휴일에도 열려있는 어린이병원으로 육아걱정 없는 동대문을 만들겠습니다." },
  { icon: "🔥", title: "무능·부패 정치 혁신", desc: "외유성 해외연수, 무능한 동대문구 정치를 주민의 힘으로 바꾸겠습니다." },
  { icon: "✊", title: "내란세력 청산", desc: "민주주의를 위협한 세력을 끝까지 책임지고 청산하겠습니다." },
  { icon: "🚇", title: "지하철 1호선 지하화", desc: "생활권을 단절하는 1호선 철로를 지하화해 회기·이문 일대를 연결하겠습니다." },
];

const CAREERS = [
  { period: "현)", label: "민주노총 서비스연맹 정책국장" },
  { period: "현)", label: "진보당 동대문지역위 달빛어린이병원 추진 공동본부장" },
  { period: "현)", label: "진보당 동대문지역위 민생위원장" },
  { period: "전)", label: "동국대학교 부총학생회장" },
  { period: "전)", label: "학교급식법 개정 100만 청원운동본부 언론홍보팀 총괄" },
];

// 샘플 소식
const INITIAL_NEWS = [
  { id: 1, date: "2026.04.10", title: "이승효 후보, 달빛어린이병원 공약 발표", body: "야간·휴일 소아과 공백을 해결하기 위해 동대문구 달빛어린이병원 설치를 공식 공약으로 발표했습니다." },
  { id: 2, date: "2026.04.07", title: "진보당 서울시의원 후보 출마 선언", body: "오직 주민편! 새로운 선택 이승효 후보가 동대문 제2선거구 출마를 공식 선언했습니다." },
  { id: 3, date: "2026.04.03", title: "지하철 1호선 지하화 추진 서명운동 시작", body: "회기동·이문동 주민들과 함께 1호선 지하화 서명운동을 시작했습니다. 1,000명을 목표로 합니다." },
];

export default function App() {
  const [page, setPage] = useState("홈");
  const [mobileMenu, setMobileMenu] = useState(false);
  const [opinions, setOpinions] = useState<any[]>([]);
  const [cheers, setCheers] = useState<any[]>([]);
  const [opinionForm, setOpinionForm] = useState({ name: "", contact: "", msg: "" });
  const [cheerForm, setCheerForm] = useState({ name: "", msg: "" });
  const [donorForm, setDonorForm] = useState({ name: "", phone: "", email: "", amount: "" });
  const [submitted, setSubmitted] = useState({ opinion: false, cheer: false, donor: false });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      try {
        const [op, ch] = await Promise.all([
          storage.get("opinions"),
          storage.get("cheers"),
        ]);
        if (op) setOpinions(JSON.parse(op.value));
        if (ch) setCheers(JSON.parse(ch.value));
      } catch(e) {}
      setLoading(false);
    }
    load();
  }, []);

  const saveOpinion = async () => {
    if (!opinionForm.msg.trim()) return;
    const next = [{ ...opinionForm, date: new Date().toLocaleDateString("ko-KR"), id: Date.now() }, ...opinions];
    setOpinions(next);
    await storage.set("opinions", JSON.stringify(next));
    setOpinionForm({ name: "", contact: "", msg: "" });
    setSubmitted(s => ({ ...s, opinion: true }));
  };

  const saveCheer = async () => {
    if (!cheerForm.msg.trim()) return;
    const next = [{ ...cheerForm, date: new Date().toLocaleDateString("ko-KR"), id: Date.now() }, ...cheers];
    setCheers(next);
    await storage.set("cheers", JSON.stringify(next));
    setCheerForm({ name: "", msg: "" });
    setSubmitted(s => ({ ...s, cheer: true }));
  };

  const saveDonor = async () => {
    if (!donorForm.name.trim()) return;
    const donors = [];
    try {
      const d = await storage.get("donors");
      if (d) donors.push(...JSON.parse(d.value));
    } catch(e) {}
    donors.push({ ...donorForm, date: new Date().toLocaleDateString("ko-KR"), id: Date.now() });
    await storage.set("donors", JSON.stringify(donors));
    setDonorForm({ name: "", phone: "", email: "", amount: "" });
    setSubmitted(s => ({ ...s, donor: true }));
  };

  const navTo = (p: string) => { setPage(p); setMobileMenu(false); window.scrollTo(0,0); };

  return (
    <div style={{ fontFamily: "'Noto Sans KR', 'Apple SD Gothic Neo', sans-serif", background: "#F5F7FF", minHeight: "100vh", color: "#0A0F2C" }}>
      {/* ── NAV ── */}
      <nav style={{ position: "sticky", top: 0, zIndex: 100, background: "rgba(255,255,255,0.95)", backdropFilter: "blur(12px)", borderBottom: "2px solid #29ABE2", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 24px", height: 60 }}>
        <div onClick={() => navTo("홈")} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ background: "#29ABE2", color: "#fff", fontWeight: 900, fontSize: 13, padding: "3px 8px", borderRadius: 4 }}>진보당</div>
          <span style={{ fontWeight: 800, fontSize: 17, color: "#29ABE2" }}>이승효</span>
        </div>
        {/* Desktop nav */}
        <div style={{ display: "flex", gap: 4 }} className="desktop-nav">
          {["홈","소개","공약","소식","의견함","후원"].map(p => (
            <button key={p} onClick={() => navTo(p)} style={{ background: page===p ? "#29ABE2" : "transparent", color: page===p ? "#fff" : "#0A0F2C", border: "none", borderRadius: 20, padding: "6px 16px", fontWeight: page===p ? 700 : 500, cursor: "pointer", fontSize: 14, transition: "all 0.2s" }}>{p}</button>
          ))}
        </div>
        {/* Mobile menu btn */}
        <button onClick={() => setMobileMenu(!mobileMenu)} style={{ display: "none", background: "none", border: "none", fontSize: 22, cursor: "pointer", color: "#29ABE2" }} className="mobile-menu-btn">☰</button>
      </nav>
      {/* Mobile dropdown */}
      {mobileMenu && (
        <div style={{ position: "fixed", top: 60, left: 0, right: 0, zIndex: 99, background: "#fff", borderBottom: "2px solid #29ABE2", padding: "8px 0" }}>
          {["홈","소개","공약","소식","의견함","후원"].map(p => (
            <button key={p} onClick={() => navTo(p)} style={{ display: "block", width: "100%", textAlign: "left", padding: "12px 24px", background: page===p ? "#E8F5FF" : "none", color: "#0A0F2C", border: "none", fontWeight: page===p ? 700 : 500, fontSize: 15, cursor: "pointer" }}>{p}</button>
          ))}
        </div>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@400;500;700;900&display=swap');
        @media(max-width:640px){ .desktop-nav{display:none!important} .mobile-menu-btn{display:block!important} }
        .btn-main { background:#29ABE2; color:#fff; border:none; border-radius:12px; padding:14px 32px; font-size:16px; font-weight:700; cursor:pointer; transition:all 0.2s; }
        .btn-main:hover { background:#1A8FCC; transform:translateY(-2px); }
        .btn-sky { background:#1A8FCC; color:#fff; border:none; border-radius:12px; padding:14px 32px; font-size:16px; font-weight:700; cursor:pointer; transition:all 0.2s; }
        .btn-sky:hover { background:#0F6E99; transform:translateY(-2px); }
        .card { background:#fff; border-radius:20px; padding:28px; box-shadow:0 4px 24px rgba(0,87,255,0.08); }
        .input-field { width:100%; padding:12px 16px; border:2px solid #e0e6f0; border-radius:12px; font-size:15px; outline:none; font-family:inherit; box-sizing:border-box; transition:border-color 0.2s; }
        .input-field:focus { border-color:#29ABE2; }
        textarea.input-field { resize:vertical; min-height:100px; }
        .tag { display:inline-block; background:#EEF9FF; color:#1A8FCC; border-radius:20px; padding:4px 12px; font-size:12px; font-weight:700; }
        .cheer-card { background:#fff; border-radius:16px; padding:20px; border-left:4px solid #E8002D; box-shadow:0 2px 12px rgba(0,87,255,0.06); margin-bottom:12px; }
      `}</style>

      <main style={{ maxWidth: 800, margin: "0 auto", padding: "0 16px 80px" }}>

      {/* ═══════════ 홈 ═══════════ */}
      {page === "홈" && <>
        {/* Hero */}
        <div style={{ background: "linear-gradient(135deg, #1A8FCC 0%, #29ABE2 60%, #5DC8F0 100%)", borderRadius: 24, margin: "20px 0 32px", overflow: "hidden", position: "relative", minHeight: 400 }}>
          <div style={{ position: "absolute", top: 0, right: 0, bottom: 0, width: "50%", overflow: "hidden" }}>
            <img src={HERO_IMG} alt="이승효 후보" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "top" }} />
            <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to right, #1A8FCC 0%, transparent 60%)" }} />
          </div>
          <div style={{ position: "relative", zIndex: 2, padding: "48px 36px" }}>
            <div style={{ background: "rgba(255,255,255,0.2)", display: "inline-block", borderRadius: 20, padding: "4px 14px", color: "#fff", fontSize: 13, fontWeight: 700, marginBottom: 12 }}>진보당 | 동대문 제2선거구</div>
            <div style={{ color: "#FFE066", fontSize: 14, fontWeight: 700, marginBottom: 8 }}>회기동 · 휘경1·2동 · 이문1·2동</div>
            <h1 style={{ color: "#fff", fontSize: "clamp(32px,6vw,52px)", fontWeight: 900, margin: "0 0 12px", lineHeight: 1.1 }}>이승효</h1>
            <p style={{ color: "rgba(255,255,255,0.9)", fontSize: 18, fontWeight: 500, margin: "0 0 24px", lineHeight: 1.5 }}>오직 주민편!<br/><strong style={{ color: "#FFE066" }}>새로운 선택</strong></p>
            <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
              <button className="btn-main" style={{ background: "#E8002D", color: "#fff" }} onClick={() => navTo("공약")}>핵심 공약 보기</button>
              <button className="btn-main" style={{ background: "rgba(255,255,255,0.2)", color: "#fff", border: "2px solid rgba(255,255,255,0.6)" }} onClick={() => navTo("후원")}>후원하기</button>
            </div>
          </div>
        </div>

        {/* 슬로건 */}
        <div style={{ textAlign: "center", padding: "24px 0 32px" }}>
          <div style={{ fontSize: "clamp(22px,4vw,36px)", fontWeight: 900, color: "#0A0F2C", lineHeight: 1.4 }}>
            <span style={{ color: "#E8002D" }}>오직 주민편!</span><br/>새로운 선택 <span style={{ color: "#29ABE2" }}>이승효</span>
          </div>
          <p style={{ color: "#555", marginTop: 12, fontSize: 16 }}>민주노총 정책국장 출신, 현장을 아는 의원</p>
        </div>

        {/* 핵심 공약 미리보기 */}
        <div style={{ marginBottom: 32 }}>
          <h2 style={{ fontSize: 22, fontWeight: 800, marginBottom: 16, color: "#29ABE2" }}>핵심 공약</h2>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(2,1fr)", gap: 14 }}>
            {PLEDGES.map((p,i) => (
              <div key={i} className="card" style={{ cursor: "pointer" }} onClick={() => navTo("공약")}>
                <div style={{ fontSize: 28, marginBottom: 8 }}>{p.icon}</div>
                <div style={{ fontWeight: 800, fontSize: 15, color: "#0A0F2C", marginBottom: 4 }}>{p.title}</div>
                <div style={{ fontSize: 13, color: "#666", lineHeight: 1.5 }}>{p.desc.slice(0,40)}...</div>
              </div>
            ))}
          </div>
        </div>

        {/* 응원 보내기 섹션 */}
        <div className="card" style={{ background: "linear-gradient(135deg, #EEF9FF, #E0F4FF)", marginBottom: 32 }}>
          <h3 style={{ fontWeight: 800, fontSize: 18, marginBottom: 4 }}>📣 응원 보내기</h3>
          <p style={{ color: "#555", fontSize: 14, marginBottom: 16 }}>이승효 후보에게 따뜻한 응원 한마디를 전해주세요!</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <input className="input-field" placeholder="이름 (선택)" value={cheerForm.name} onChange={e => setCheerForm(f => ({...f, name: e.target.value}))} />
            <textarea className="input-field" placeholder="응원 메시지를 입력해주세요" value={cheerForm.msg} onChange={e => setCheerForm(f => ({...f, msg: e.target.value}))} />
            {submitted.cheer
              ? <div style={{ color: "#29ABE2", fontWeight: 700, textAlign: "center", padding: 12 }}>✅ 응원 메시지가 전달되었습니다!</div>
              : <button className="btn-main" onClick={saveCheer}>응원 보내기</button>
            }
          </div>
          {cheers.length > 0 && (
            <div style={{ marginTop: 20 }}>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 12, color: "#29ABE2" }}>응원 메시지 {cheers.length}개</div>
              {cheers.slice(0,3).map(c => (
                <div key={c.id} className="cheer-card">
                  <div style={{ fontWeight: 700, fontSize: 14 }}>{c.name || "익명"} <span style={{ color: "#aaa", fontWeight: 400, fontSize: 12 }}>{c.date}</span></div>
                  <div style={{ fontSize: 14, color: "#333", marginTop: 4 }}>{c.msg}</div>
                </div>
              ))}
            </div>
          )}
        </div>
      </>}

      {/* ═══════════ 소개 ═══════════ */}
      {page === "소개" && <>
        <div style={{ padding: "32px 0 16px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 900, color: "#29ABE2", margin: 0 }}>후보 소개</h1>
        </div>

        <div className="card" style={{ marginBottom: 20, display: "flex", gap: 24, alignItems: "flex-start", flexWrap: "wrap" }}>
          <img src={SITTING_IMG} alt="이승효" style={{ width: 140, borderRadius: 16, objectFit: "cover", flexShrink: 0 }} />
          <div style={{ flex: 1, minWidth: 200 }}>
            <h2 style={{ fontSize: 28, fontWeight: 900, margin: "0 0 8px" }}>이승효</h2>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 16 }}>
              <span className="tag">진보당</span>
              <span className="tag">동대문 제2선거구</span>
              <span className="tag">회기·휘경·이문</span>
            </div>
            <p style={{ color: "#444", lineHeight: 1.7, fontSize: 15 }}>
              광주에서 태어나 동국대를 졸업하고, 청년 시절부터 학생운동·급식법 개정운동을 이끌어온 현장 활동가입니다. 지금은 민주노총 서비스연맹 정책국장으로 노동자의 목소리를 제도로 만드는 일을 하고 있습니다.
            </p>
          </div>
        </div>

        <div className="card" style={{ marginBottom: 20 }}>
          <h3 style={{ fontWeight: 800, fontSize: 18, marginBottom: 16, color: "#29ABE2" }}>약력</h3>
          {CAREERS.map((c,i) => (
            <div key={i} style={{ display: "flex", gap: 12, padding: "10px 0", borderBottom: i < CAREERS.length-1 ? "1px solid #f0f0f0" : "none" }}>
              <span style={{ color: "#29ABE2", fontWeight: 700, fontSize: 13, minWidth: 30 }}>{c.period}</span>
              <span style={{ fontSize: 15, color: "#0A0F2C" }}>{c.label}</span>
            </div>
          ))}
          <div style={{ padding: "10px 0", borderTop: "1px solid #f0f0f0", marginTop: 4 }}>
            <div style={{ display: "flex", gap: 12 }}>
              <span style={{ color: "#888", fontWeight: 700, fontSize: 13, minWidth: 30 }}>학력</span>
              <span style={{ fontSize: 15, color: "#0A0F2C" }}>동국대학교 사범대학 졸업 / 광주 고려고등학교 졸업</span>
            </div>
          </div>
        </div>

        <div className="card" style={{ background: "linear-gradient(135deg,#1A8FCC,#29ABE2)", color: "#fff", textAlign: "center" }}>
          <div style={{ fontSize: 22, fontWeight: 900, marginBottom: 8, color: "#FFE066" }}>오직 주민편!</div>
          <div style={{ fontSize: 28, fontWeight: 900 }}>새로운 선택 이승효</div>
          <div style={{ marginTop: 12, opacity: 0.85, fontSize: 15 }}>회기동 · 휘경1·2동 · 이문1·2동 주민과 함께 만들어가겠습니다</div>
        </div>
      </>}

      {/* ═══════════ 공약 ═══════════ */}
      {page === "공약" && <>
        <div style={{ padding: "32px 0 16px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 900, color: "#29ABE2", margin: 0 }}>핵심 공약</h1>
          <p style={{ color: "#555", marginTop: 8 }}>말이 아닌 행동으로, 주민의 삶을 바꾸는 약속</p>
        </div>
        {PLEDGES.map((p, i) => (
          <div key={i} className="card" style={{ marginBottom: 16, display: "flex", gap: 20, alignItems: "flex-start" }}>
            <div style={{ fontSize: 44, minWidth: 56, textAlign: "center" }}>{p.icon}</div>
            <div>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
                <span style={{ background: "#29ABE2", color: "#fff", borderRadius: "50%", width: 24, height: 24, display: "inline-flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 900 }}>{i+1}</span>
                <h3 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>{p.title}</h3>
              </div>
              <p style={{ color: "#444", lineHeight: 1.7, margin: 0, fontSize: 15 }}>{p.desc}</p>
            </div>
          </div>
        ))}
      </>}

      {/* ═══════════ 소식 ═══════════ */}
      {page === "소식" && <>
        <div style={{ padding: "32px 0 16px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 900, color: "#29ABE2", margin: 0 }}>활동 소식</h1>
        </div>
        {INITIAL_NEWS.map(n => (
          <div key={n.id} className="card" style={{ marginBottom: 16 }}>
            <div style={{ color: "#29ABE2", fontSize: 13, fontWeight: 700, marginBottom: 6 }}>{n.date}</div>
            <h3 style={{ margin: "0 0 10px", fontSize: 18, fontWeight: 800 }}>{n.title}</h3>
            <p style={{ color: "#555", lineHeight: 1.7, margin: 0, fontSize: 15 }}>{n.body}</p>
          </div>
        ))}
      </>}

      {/* ═══════════ 의견함 ═══════════ */}
      {page === "의견함" && <>
        <div style={{ padding: "32px 0 16px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 900, color: "#29ABE2", margin: 0 }}>주민 의견함</h1>
          <p style={{ color: "#555", marginTop: 8 }}>여러분의 의견이 정책이 됩니다</p>
        </div>

        <div className="card" style={{ marginBottom: 24 }}>
          <h3 style={{ fontWeight: 800, fontSize: 16, marginBottom: 16 }}>의견 보내기</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            <input className="input-field" placeholder="이름 (선택)" value={opinionForm.name} onChange={e => setOpinionForm(f => ({...f, name: e.target.value}))} />
            <input className="input-field" placeholder="연락처 (선택)" value={opinionForm.contact} onChange={e => setOpinionForm(f => ({...f, contact: e.target.value}))} />
            <textarea className="input-field" style={{ minHeight: 140 }} placeholder="의견을 자유롭게 적어주세요" value={opinionForm.msg} onChange={e => setOpinionForm(f => ({...f, msg: e.target.value}))} />
            {submitted.opinion
              ? <div style={{ color: "#29ABE2", fontWeight: 700, textAlign: "center", padding: 16 }}>✅ 의견이 접수되었습니다. 감사합니다!</div>
              : <button className="btn-main" onClick={saveOpinion}>의견 보내기</button>
            }
          </div>
        </div>

        {opinions.length > 0 && (
          <div>
            <h3 style={{ fontWeight: 800, fontSize: 16, marginBottom: 12 }}>접수된 의견 ({opinions.length})</h3>
            {opinions.map(o => (
              <div key={o.id} className="cheer-card" style={{ borderLeftColor: "#E8002D" }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{o.name || "익명"} <span style={{ color: "#aaa", fontWeight: 400, fontSize: 12 }}>{o.date}</span></div>
                <div style={{ fontSize: 14, color: "#333", marginTop: 4 }}>{o.msg}</div>
              </div>
            ))}
          </div>
        )}
      </>}

      {/* ═══════════ 후원 ═══════════ */}
      {page === "후원" && <>
        <div style={{ padding: "32px 0 16px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 900, color: "#29ABE2", margin: 0 }}>후원인 정보 입력</h1>
          <p style={{ color: "#555", marginTop: 8 }}>주민 여러분의 후원이 새로운 동대문을 만듭니다</p>
        </div>

        <div className="card" style={{ marginBottom: 24, background: "linear-gradient(135deg,#1A8FCC,#29ABE2)", color: "#fff" }}>
          <div style={{ fontSize: 16, fontWeight: 700, marginBottom: 4, opacity: 0.9 }}>후원 계좌 안내</div>
          <div style={{ fontSize: 20, fontWeight: 900 }}>진보당 후원 채널을 통해 후원 가능합니다</div>
          <div style={{ marginTop: 8, opacity: 0.85, fontSize: 14 }}>선거관계로 인해 후원금은 법적 절차에 따라 처리됩니다</div>
        </div>

        <div className="card">
          <h3 style={{ fontWeight: 800, fontSize: 16, marginBottom: 16 }}>후원인 정보</h3>
          {submitted.donor ? (
            <div style={{ textAlign: "center", padding: "32px 0" }}>
              <div style={{ fontSize: 48, marginBottom: 16 }}>🎉</div>
              <div style={{ fontSize: 20, fontWeight: 800, color: "#29ABE2", marginBottom: 8 }}>감사합니다!</div>
              <div style={{ color: "#555" }}>후원인 정보가 접수되었습니다.<br/>이승효 후보가 끝까지 보답하겠습니다.</div>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              <input className="input-field" placeholder="성함 *" value={donorForm.name} onChange={e => setDonorForm(f => ({...f, name: e.target.value}))} />
              <input className="input-field" placeholder="연락처" value={donorForm.phone} onChange={e => setDonorForm(f => ({...f, phone: e.target.value}))} />
              <input className="input-field" placeholder="이메일" value={donorForm.email} onChange={e => setDonorForm(f => ({...f, email: e.target.value}))} />
              <input className="input-field" placeholder="후원 금액 (원)" value={donorForm.amount} onChange={e => setDonorForm(f => ({...f, amount: e.target.value}))} />
              <button className="btn-main" onClick={saveDonor}>후원 신청</button>
            </div>
          )}
        </div>
      </>}

      </main>

      {/* Bottom nav (mobile) */}
      <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, background: "#fff", borderTop: "1px solid #e0e6f0", display: "flex", zIndex: 50 }} className="bottom-nav">
        {["홈","소개","공약","소식","의견함","후원"].map(p => (
          <button key={p} onClick={() => navTo(p)} style={{ flex: 1, padding: "10px 0", background: "none", border: "none", fontSize: 11, fontWeight: page===p ? 800 : 500, color: page===p ? "#29ABE2" : "#888", cursor: "pointer", fontFamily: "inherit" }}>
            {{"홈":"🏠","소개":"👤","공약":"📋","소식":"📰","의견함":"💬","후원":"💙"}[p]}<br/>{p}
          </button>
        ))}
      </div>
      <style>{`.bottom-nav { display: none!important; } @media(max-width:640px){ .bottom-nav{ display:flex!important; } }`}</style>
    </div>
  );
}
